class Reviewer:

    def __init__(self):
        pass

    def build_task_tree(
        self,
        task_tree: TaskTree,
        context: str,
        llm=get_llm(
            base_url=DefaultConfig.agent_api_base,
            api_key=DefaultConfig.agent_api_key,
            model_name=DefaultConfig.agent_model,
        ),
    ) -> TaskTree:
        agent = Agent(llm=llm)

        visited = set()
        root = task_tree.get_root_node()
        agent.set_system_prompt(
            system_prompt.format(
                task=root,
                context=context,
            )
        )

        init_start = True
        while True:
            leaves = task_tree.get_leaf_nodes()
            if not leaves:
                break
            flag = False
            # agent.print_history()

            for leaf in leaves:
                if str(leaf) in visited:
                    continue
                visited.add(str(leaf))

                if not init_start:
                    res = agent.invoke_with_structured_output(
                        decision_prompt.format(
                            refined_task_tree=task_tree,
                            task=leaf,
                        ),
                        schema=Evaluation,
                    ).value()
                    agent.remove_last_k_messages(2)
                    if not res:
                        continue

                res = agent.invoke_with_structured_output(
                    expand_node_prompt.format(
                        refined_task_tree=task_tree,
                        task=leaf,
                    ),
                    schema=Node,
                )
                agent.remove_last_k_messages(2)

                leaf.name = res.name
                leaf.spec = res.spec
                task_tree.update_node(leaf)

                for node in res.subtasks:
                    node = TaskNode(
                        name=node.name,
                        spec=node.spec,
                    )
                    task_tree.add_node(node, parent=leaf)
                    flag = True

                # print(task_tree)
                # input("Press Enter to continue...")

            init_start = False
            if not flag:
                break

        return task_tree

    def summarize_exeprience(
        self,
        task_tree: TaskTree,
        context: str,
        llm=get_llm(
            base_url=DefaultConfig.code_api_base,
            api_key=DefaultConfig.code_api_key,
            model_name=DefaultConfig.code_model,
        ),
    ) -> TaskTree:
        agent = Agent(llm=llm)
        agent.set_system_prompt(summarize_system_prompt.format(context=context))

        queue = [task_tree.get_root_node()]

        while queue:
            # agent.print_history()
            task = queue.pop(0)

            task.summary = agent.invoke(
                summarize_node_prompt.format(task=task, task_tree=task_tree)
            )
            agent.remove_last_k_messages(2)
            task_tree.update_node(task)

            queue.extend(task_tree.get_child_nodes(task))

            # input("Press Enter to continue...")

        return task_tree


